using Apex.Modules.Accounting.ChartOfAccounts.Repositories;using Microsoft.AspNetCore.Mvc;
namespace Apex.Modules.Accounting.ChartOfAccounts.UseCases.GetAccountTree;
internal sealed record SubsidiaryNode(long Id,string Code,string Name,string Nature,string DetailAccountType,string Status);internal sealed record GeneralNode(long Id,string Code,string Name,string Nature,string Status,IReadOnlyList<SubsidiaryNode> SubsidiaryAccounts);internal sealed record ClassNode(long Id,string Code,string Name,string Status,IReadOnlyList<GeneralNode> GeneralAccounts);
internal sealed class GetAccountTreeHandler(IAccountClassReadRepository classes,IGeneralAccountReadRepository generals,ISubsidiaryAccountReadRepository subsidiaries){public async Task<IReadOnlyList<ClassNode>> HandleAsync(bool includeArchived,CancellationToken ct){var classRows=await classes.ListAsync(includeArchived,ct);var generalRows=await generals.ListAsync(includeArchived,ct);var subsidiaryRows=await subsidiaries.ListAsync(includeArchived,ct);var children=subsidiaryRows.GroupBy(x=>x.GeneralAccountId).ToDictionary(x=>x.Key,x=>(IReadOnlyList<SubsidiaryNode>)x.Select(s=>new SubsidiaryNode(s.Id,s.Code,s.Name,s.Nature,s.DetailAccountType,s.Status)).ToList());var middle=generalRows.GroupBy(x=>x.AccountClassId).ToDictionary(x=>x.Key,x=>(IReadOnlyList<GeneralNode>)x.Select(a=>new GeneralNode(a.Id,a.Code,a.Name,a.Nature,a.Status,children.GetValueOrDefault(a.Id,[]))).ToList());return classRows.Select(a=>new ClassNode(a.Id,a.Code,a.Name,a.Status,middle.GetValueOrDefault(a.Id,[]))).ToList();}}
internal static class GetAccountTreeEndpoint{internal static RouteGroupBuilder MapGetAccountTreeEndpoint(this RouteGroupBuilder g){g.MapGet("/tree",async([FromQuery]bool? includeArchived,[FromServices]GetAccountTreeHandler h,CancellationToken ct)=>Results.Ok(await h.HandleAsync(includeArchived??false,ct))).WithName("GetAccountTree");return g;}}
